  1→using System;
  2→using System.IO;
  3→using System.Text;
  4→using System.Text.RegularExpressions;
  5→
  6→namespace AssembleMonitor.Features.Communication;
  7→
  8→/// <summary>
  9→/// LS XGT FEnet 프로토콜 패킷 생성/파싱
 10→/// XGT 전용 프로토콜 (포트 2004)
 11→///
 12→/// 헤더 구조 (20바이트):
 13→/// [0-9]   CompanyID: "LSIS-XGT\0\0"
 14→/// [10-11] PLC Info
 15→/// [12]    CPU Info (0xA0 = XGI/XGR/XEC)
 16→/// [13]    Source of Frame (0x33=요청, 0x11=응답)
 17→/// [14-15] Invoke ID
 18→/// [16-17] Data Length (바이트 20 이후 길이)
 19→/// [18]    Slot/Position
 20→/// [19]    BCC
 21→///
 22→/// 애플리케이션 데이터 (20바이트~):
 23→/// [20-21] Command (0x0054=RSS, 0x0058=WSS)
 24→/// [22-23] Data Type (0x0014=WORD)
 25→/// [24-25] Reserved (0x0000) ← 필수!
 26→/// [26+]   데이터 프레임
 27→///
 28→/// 주소 변환 규칙 (XGT FEnet):
 29→/// - Word 읽기/쓰기 시 주소를 Byte 기반으로 변환
 30→/// - %MW100 → %MB200 (index×2), count도 BYTE 단위
 31→/// - %IW0.0.0 → %IB0.0.0, %QW → %QB 등
 32→/// </summary>
 33→public static class XgtProtocol
 34→{
 35→    // CompanyID (10바이트)
 36→    private static readonly byte[] COMPANY_ID =
 37→        [0x4C, 0x53, 0x49, 0x53, 0x2D, 0x58, 0x47, 0x54, 0x00, 0x00]; // "LSIS-XGT\0\0"
 38→
 39→    private const byte CPU_INFO = 0xA0;        // XGI/XGR/XEC
 40→    private const byte SOURCE_REQUEST = 0x33;   // PC → PLC
 41→    private const byte SOURCE_RESPONSE = 0x11;  // PLC → PC
 42→
 43→    // 명령어
 44→    private const ushort CMD_RSS_REQ = 0x0054;  // 연속 읽기 요청
 45→    private const ushort CMD_RSS_RSP = 0x0055;  // 연속 읽기 응답
 46→    private const ushort CMD_WSS_REQ = 0x0058;  // 연속 쓰기 요청
 47→    private const ushort CMD_WSS_RSP = 0x0059;  // 연속 쓰기 응답
 48→
 49→    // 데이터 타입
 50→    private const ushort DATA_TYPE_WORD = 0x0014;
 51→
 52→    // %MW100 → %MB200 변환 정규식 (M/D/L/K/F 영역)
 53→    private static readonly Regex RxWordAddr =
 54→        new(@"^%([MDLKF])W(\d+)$", RegexOptions.Compiled | RegexOptions.IgnoreCase);
 55→
 56→    // %IW0.0.0 → %IB0.0.0 / %QW0.0.0 → %QB0.0.0 변환
 57→    private static readonly Regex RxIoWordAddr =
 58→        new(@"^%([IQU])W(.+)$", RegexOptions.Compiled | RegexOptions.IgnoreCase);
 59→
 60→    /// <summary>
 61→    /// Word 주소를 Byte 주소로 변환 (XGT FEnet 규칙)
 62→    /// %MW100 → %MB200, %IW0.0.0 → %IB0.0.0, %UW0.9.1 → %UB0.9.1
 63→    /// </summary>
 64→    private static string ConvertToByteAddress(string wordAddress)
 65→    {
 66→        // M/D/L/K/F 영역: %MW100 → %MB200 (index×2)
 67→        var m = RxWordAddr.Match(wordAddress);
 68→        if (m.Success)
 69→        {
 70→            var device = m.Groups[1].Value.ToUpper();
 71→            var index = int.Parse(m.Groups[2].Value);
 72→            return $"%{device}B{index * 2}";
 73→        }
 74→
 75→        // I/Q/U 영역: %IW0.0.0 → %IB0.0.0 (dot 형식은 index 변환 불요)
 76→        var m2 = RxIoWordAddr.Match(wordAddress);
 77→        if (m2.Success)
 78→        {
 79→            var device = m2.Groups[1].Value.ToUpper();
 80→            var rest = m2.Groups[2].Value;
 81→            return $"%{device}B{rest}";
 82→        }
 83→
 84→        // 변환 불가 — 원본 그대로 반환
 85→        return wordAddress;
 86→    }
 87→
 88→    /// <summary>
 89→    /// 연속 WORD 읽기 요청 패킷 (RSS)
 90→    /// startAddress: %MW100 형태 → 내부에서 %MB200으로 변환
 91→    /// </summary>
 92→    public static byte[] BuildReadRequest(string startAddress, ushort wordCount)
 93→    {
 94→        var byteAddr = ConvertToByteAddress(startAddress);
 95→        var addrBytes = Encoding.ASCII.GetBytes(byteAddr);
 96→        var addrLen = (ushort)addrBytes.Length;
 97→        var byteCount = (ushort)(wordCount * 2);
 98→
 99→        // 데이터 프레임: Reserved(2) + 블록수(2) + 주소길이(2) + 주소(N) + 읽기BYTE수(2)
100→        var dataFrameLen = 2 + 2 + 2 + addrLen + 2;
101→
102→        return BuildPacket(CMD_RSS_REQ, dataFrameLen, writer =>
103→        {
104→            writer.Write((ushort)0x0000);   // Reserved (필수!)
105→            writer.Write((ushort)1);        // 블록 수
106→            writer.Write(addrLen);          // 주소 문자열 길이
107→            writer.Write(addrBytes);        // 주소 문자열 (BYTE 기반)
108→            writer.Write(byteCount);        // 읽을 BYTE 수
109→        });
110→    }
111→
112→    /// <summary>
113→    /// 연속 WORD 쓰기 요청 패킷 (WSS)
114→    /// startAddress: %MW200 형태 → 내부에서 %MB400으로 변환
115→    /// </summary>
116→    public static byte[] BuildWriteRequest(string startAddress, ushort[] values)
117→    {
118→        var byteAddr = ConvertToByteAddress(startAddress);
119→        var addrBytes = Encoding.ASCII.GetBytes(byteAddr);
120→        var addrLen = (ushort)addrBytes.Length;
121→        var wordCount = (ushort)values.Length;
122→        var byteCount = (ushort)(wordCount * 2);
123→
124→        // 데이터 프레임: Reserved(2) + 블록수(2) + 주소길이(2) + 주소(N) + BYTE수(2) + 데이터(N*2)
125→        var dataFrameLen = 2 + 2 + 2 + addrLen + 2 + byteCount;
126→
127→        return BuildPacket(CMD_WSS_REQ, dataFrameLen, writer =>
128→        {
129→            writer.Write((ushort)0x0000);   // Reserved (필수!)
130→            writer.Write((ushort)1);        // 블록 수
131→            writer.Write(addrLen);          // 주소 문자열 길이
132→            writer.Write(addrBytes);        // 주소 문자열 (BYTE 기반)
133→            writer.Write(byteCount);        // BYTE 수
134→            foreach (var val in values)
135→                writer.Write(val);
136→        });
137→    }
138→
139→    /// <summary>
140→    /// 응답 패킷 파싱 결과
141→    /// </summary>
142→    public record ParseResult(
143→        bool Success,
144→        ushort Command,
145→        ushort DataType,
146→        ushort[]? Words,
147→        string ErrorInfo);
148→
149→    /// <summary>
150→    /// 응답 패킷 파싱 (범용 — 읽기/쓰기 모두)
151→    /// 응답에도 Reserved(2) 포함: cmd(2)+dtype(2)+reserved(2)+data
152→    /// </summary>
153→    public static ParseResult ParseResponse(byte[] response, int length)
154→    {
155→        // 최소 헤더(20) + cmd(2) + dtype(2) + reserved(2) = 26바이트
156→        if (length < 26)
157→            return new(false, 0, 0, null,
158→                $"응답 너무 짧음: {length}B (최소 26B 필요)");
159→
160→        // 헤더 파싱 (20바이트 기준)
161→        var source = response[13];
162→        var dataLen = BitConverter.ToUInt16(response, 16);
163→        var command = BitConverter.ToUInt16(response, 20);
164→        var dataType = BitConverter.ToUInt16(response, 22);
165→        // [24-25] = Reserved (스킵)
166→
167→        // 방향 확인
168→        if (source != SOURCE_RESPONSE)
169→            return new(false, command, dataType, null,
170→                $"응답 Source=0x{source:X2} (0x11 예상)");
171→
172→        // cmd(2) + dtype(2) + reserved(2) 이후 = 바이트 26부터
173→        // 단, 응답에 Reserved가 없을 수도 있으므로 24부터 시도
174→        var appDataOffset = 24;
175→        var appDataLen = length - appDataOffset;
176→
177→        if (appDataLen < 2)
178→            return new(false, command, dataType, null,
179→                $"데이터 없음: cmd=0x{command:X4}, dataLen={dataLen}, total={length}B");
180→
181→        // 읽기 응답 (0x0055)
182→        if (command == CMD_RSS_RSP)
183→            return ParseReadData(response, length, appDataOffset);
184→
185→        // 쓰기 응답 (0x0059)
186→        if (command == CMD_WSS_RSP)
187→            return ParseWriteData(response, length, appDataOffset);
188→
189→        // 알 수 없는 명령
190→        return new(false, command, dataType, null,
191→            $"미지원 응답 cmd=0x{command:X4}");
192→    }
193→
194→    private static ParseResult ParseReadData(byte[] response, int length, int offset)
195→    {
196→        // [offset+0,1] = 블록 수
197→        var blockCount = BitConverter.ToUInt16(response, offset);
198→        offset += 2;
199→
200→        if (offset + 2 > length)
201→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
202→                $"블록 수={blockCount}, 데이터 부족 ({length}B)");
203→
204→        // [offset+0,1] = 데이터 바이트 수
205→        var dataByteCount = BitConverter.ToUInt16(response, offset);
206→        offset += 2;
207→
208→        // 에러 체크: dataByteCount가 0xFFFF이면 에러 코드
209→        if (dataByteCount == 0xFFFF)
210→        {
211→            ushort errInfo = (offset + 2 <= length)
212→                ? BitConverter.ToUInt16(response, offset) : (ushort)0;
213→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
214→                $"PLC 에러: code=0xFFFF, info=0x{errInfo:X4}");
215→        }
216→
217→        // 에러 체크: dataByteCount가 0이거나 비정상이면
218→        if (dataByteCount == 0 || offset + dataByteCount > length)
219→        {
220→            var remaining = length - offset + 2;
221→            var dump = BitConverter.ToString(response, offset - 2,
222→                Math.Min(remaining + 2, length - offset + 2));
223→            return new(false, CMD_RSS_RSP, DATA_TYPE_WORD, null,
224→                $"블록={blockCount}, 데이터크기={dataByteCount}, 잔여={dump}");
225→        }
226→
227→        // WORD 배열 추출
228→        var wordCount = dataByteCount / 2;
229→        var words = new ushort[wordCount];
230→        for (int i = 0; i < wordCount; i++)
231→        {
232→            if (offset + 2 > length) break;
233→            words[i] = BitConverter.ToUInt16(response, offset);
234→            offset += 2;
235→        }
236→
237→        return new(true, CMD_RSS_RSP, DATA_TYPE_WORD, words, "OK");
238→    }
239→
240→    private static ParseResult ParseWriteData(byte[] response, int length, int offset)
241→    {
242→        if (offset + 2 > length)
243→            return new(false, CMD_WSS_RSP, DATA_TYPE_WORD, null,
244→                $"쓰기 응답 데이터 부족 ({length}B)");
245→
246→        var blockCount = BitConverter.ToUInt16(response, offset);
247→        return new(blockCount > 0, CMD_WSS_RSP, DATA_TYPE_WORD, null,
248→            blockCount > 0 ? "쓰기 OK" : "쓰기 실패 (block=0)");
249→    }
250→
251→    /// <summary>
252→    /// 응답 헤더를 사람이 읽을 수 있게 덤프
253→    /// </summary>
254→    public static string DumpResponseHeader(byte[] response, int length)
255→    {
256→        if (length < 20) return $"[헤더 부족: {length}B]";
257→
258→        var sb = new StringBuilder();
259→        var companyId = Encoding.ASCII.GetString(response, 0, 8).TrimEnd('\0');
260→        sb.Append($"ID={companyId}");
261→        sb.Append($" src=0x{response[13]:X2}");
262→        sb.Append($" len={BitConverter.ToUInt16(response, 16)}");
263→        if (length >= 22) sb.Append($" cmd=0x{BitConverter.ToUInt16(response, 20):X4}");
264→        if (length >= 24) sb.Append($" type=0x{BitConverter.ToUInt16(response, 22):X4}");
265→        return sb.ToString();
266→    }
267→
268→    private static byte[] BuildPacket(ushort command, int dataFrameLen,
269→        Action<BinaryWriter> writeDataFrame)
270→    {
271→        using var ms = new MemoryStream();
272→        using var writer = new BinaryWriter(ms);
273→
274→        // --- 헤더 (20바이트) ---
275→        writer.Write(COMPANY_ID);               // [0-9] "LSIS-XGT\0\0"
276→        writer.Write((ushort)0x0000);           // [10-11] PLC Info
277→        writer.Write(CPU_INFO);                 // [12] CPU Info
278→        writer.Write(SOURCE_REQUEST);           // [13] Source = 요청
279→        writer.Write((ushort)0x0000);           // [14-15] Invoke ID
280→
281→        // [16-17] Length = cmd(2) + dtype(2) + dataFrame (Reserved 포함)
282→        var appLen = (ushort)(4 + dataFrameLen);
283→        writer.Write(appLen);
284→
285→        writer.Write((byte)0x00);               // [18] Slot/Position
286→        writer.Write((byte)0x00);               // [19] BCC
287→
288→        // --- 애플리케이션 ---
289→        writer.Write(command);                  // [20-21] Command
290→        writer.Write(DATA_TYPE_WORD);           // [22-23] Data Type
291→
292→        // --- 데이터 프레임 (Reserved + block + addr + count) ---
293→        writeDataFrame(writer);
294→
295→        return ms.ToArray();
296→    }
297→}
