 1→(* ============================================================ *)
 2→(* PROG_SAFETY: 안전 인터록 + Watchdog                         *)
 3→(* 역할: PC 통신 감시, EMO 처리, 전출력 차단                    *)
 4→(* 실행 순서: 가장 먼저 (PROG_IO_MAP, PROG_SERVO 보다 선행)     *)
 5→(* ============================================================ *)
 6→
 7→(* 1. 입력 읽기 *)
 8→wHeartbeat := %MW500 AND 16#00FF;
 9→bPcReady := %MW500.8;
10→bPcEmoReq := %MW500.9;
11→bEmoInput := %IX0.0.11;
12→
13→(* 2. Watchdog 감시 — 500ms 무변화 시 통신 두절 *)
14→IF wHeartbeat <> g_WD_PrevCount THEN
15→    g_WD_PrevCount := wHeartbeat;
16→    g_WD_Changed := TRUE;
17→ELSE
18→    g_WD_Changed := FALSE;
19→END_IF;
20→
21→g_WD_TON(IN := NOT g_WD_Changed, PT := T#500MS);
22→g_WD_Timeout := g_WD_TON.Q;
23→g_PC_Ready := bPcReady AND (NOT g_WD_Timeout);
24→
25→(* 3. EMO — NC접점 반전 + PC 요청 *)
26→g_EMO_Active := (NOT bEmoInput) OR bPcEmoReq;
27→
28→(* 4. SafetyStop 판정 *)
29→g_SafetyStop := g_WD_Timeout OR g_EMO_Active OR (NOT g_PC_Ready);
30→
31→(* 5. SafetyStop 시 출력 강제 OFF *)
32→IF g_SafetyStop THEN
33→    %MW200 := 0;
34→    %MW201 := 0;
35→    %MW202 := 0;
36→    %MW203 := 0;
37→    %MW204 := 0;
38→    %MW205 := 0;
39→    %MW206 := 0;
40→    %MW207 := 0;
41→    %MW208 := 0;
42→    %MW209 := 0;
43→    g_bStopExec := TRUE;
44→END_IF;
45→
46→(* 6. PLC → PC 상태 비트 갱신 (MW501) *)
47→%MW501 := 0;
48→
49→IF NOT g_WD_Timeout THEN
50→    %MW501 := %MW501 OR 16#0001;
51→END_IF;
52→
53→IF g_EMO_Active THEN
54→    %MW501 := %MW501 OR 16#0002;
55→END_IF;
56→
57→IF %MW400.1 THEN
58→    %MW501 := %MW501 OR 16#0004;
59→END_IF;
60→
61→IF g_WD_Timeout THEN
62→    %MW501 := %MW501 OR 16#0008;
63→END_IF;
64→
65→%MW501 := %MW501 OR 16#0010;
66→
67→(* 7. PLC 하트비트 카운터 → MW501 상위 바이트 (bit8~15) *)
68→g_ScanCount := g_ScanCount + 1;
69→IF g_ScanCount > 255 THEN
70→    g_ScanCount := 0;
71→END_IF;
72→%MW501 := %MW501 OR INT_TO_WORD(g_ScanCount * 256);
